```class Solution {
    public int kIncreasing(int[] arr, int k) {
        int result = 0;
        for (int i = 0; i < arr.length; i++) {
            for (int j = i + k; j < arr.length; j++) {
                if (arr[j] < arr[i] && j - i >= k) {
                    result++;
                }
            }
        }
        return result;
    }
}
